import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import he from '../i18n/he.json';

const API          = 'https://pizza-story-backend-u6n0.onrender.com';
const DELIVERY_FEE = 15;
const STORE_ADDRESS = 'רחוב הפיצה 1, תל אביב';
const GOLD         = '#FFC107';
const DARK         = '#1A1A1A';

const PROMO_CODES = {
  PIZZA10:  { type: 'percent',  value: 10, label: '10% הנחה' },
  PIZZA20:  { type: 'percent',  value: 20, label: '20% הנחה' },
  FREESHIP: { type: 'delivery', value: 0,  label: 'משלוח חינם' },
};

// ── Circular Step Number ─────────────────────────────────────────────────────
function StepBadge({ n, done }) {
  return (
    <div
      className="w-7 h-7 rounded-full flex items-center justify-center font-black text-sm flex-shrink-0"
      style={done
        ? { background: GOLD, color: DARK }
        : { background: '#f3f4f6', color: '#9ca3af' }
      }
    >
      {done ? (
        <svg width="13" height="13" viewBox="0 0 24 24" fill="none"
          stroke={DARK} strokeWidth="3" strokeLinecap="round">
          <polyline points="20 6 9 17 4 12"/>
        </svg>
      ) : n}
    </div>
  );
}

// ── Big Toggle Option ────────────────────────────────────────────────────────
function BigOption({ active, onClick, emoji, title, sub }) {
  return (
    <button
      type="button"
      onClick={onClick}
      className="flex-1 flex flex-col items-center justify-center py-5 rounded-2xl border-2 transition active:scale-95 font-bold text-sm"
      style={active
        ? { borderColor: GOLD, background: '#FFC10712', color: DARK }
        : { borderColor: '#e5e7eb', background: 'white', color: '#9ca3af' }
      }
    >
      <span className="text-3xl mb-1.5">{emoji}</span>
      <span style={{ color: active ? DARK : '#9ca3af', fontWeight: 700 }}>{title}</span>
      {sub && (
        <span className="text-xs mt-0.5 font-semibold" style={{ color: active ? '#6b7280' : '#d1d5db' }}>
          {sub}
        </span>
      )}
    </button>
  );
}

export default function CheckoutForm() {
  const navigate = useNavigate();
  const cart = JSON.parse(localStorage.getItem('cart') || '{}');
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');

  const [form, setForm] = useState({
    name: auth.name || '', phone: auth.phone || '',
    address: '', kitchenNotes: '', driverNotes: '', paymentMethod: 'cash',
  });
  const [fulfillmentType, setFulfillmentType] = useState('delivery');
  const [promoInput,   setPromoInput]   = useState('');
  const [appliedPromo, setAppliedPromo] = useState(null);
  const [promoError,   setPromoError]   = useState('');
  const [addressPrefilled, setAddressPrefilled] = useState(false);
  const [loading,      setLoading]      = useState(false);
  const [showPromo,    setShowPromo]    = useState(false);

  useEffect(() => {
    if (!auth.phone) return;
    axios.get(`${API}/api/orders/history/${auth.phone}`)
      .then(res => {
        const last = res.data.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt))[0];
        if (!last) return;
        const addr = last.address || last.deliveryAddress;
        if (addr) { setForm(f => ({ ...f, address: addr })); setAddressPrefilled(true); }
        if (last.name && !auth.name) setForm(f => ({ ...f, name: last.name }));
      }).catch(() => {});
  }, []);

  if (!cart.toppings) return null;

  const handleChange = e => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const applyPromo = () => {
    const code = promoInput.trim().toUpperCase();
    if (PROMO_CODES[code]) { setAppliedPromo({ code, ...PROMO_CODES[code] }); setPromoError(''); }
    else { setPromoError(he.promo_invalid); setAppliedPromo(null); }
  };
  const removePromo = () => { setAppliedPromo(null); setPromoInput(''); setPromoError(''); };

  const baseTotal   = cart.total || 30;
  const isFreeShip  = appliedPromo?.type === 'delivery';
  const deliveryFee = fulfillmentType === 'delivery' && !isFreeShip ? DELIVERY_FEE : 0;
  const discountAmt = appliedPromo?.type === 'percent'
    ? Math.round(baseTotal * appliedPromo.value / 100) : 0;
  const finalTotal  = baseTotal + deliveryFee - discountAmt;

  const handleSubmit = async e => {
    e.preventDefault();
    if (fulfillmentType === 'delivery' && !form.address.trim()) {
      alert('יש להכניס כתובת למשלוח'); return;
    }
    setLoading(true);
    try {
      await axios.post(`${API}/api/orders`, {
        name: form.name, phone: form.phone, customerPhone: form.phone,
        address:         fulfillmentType === 'delivery' ? form.address : STORE_ADDRESS,
        deliveryAddress: fulfillmentType === 'delivery' ? form.address : '',
        paymentMethod: form.paymentMethod,
        paymentStatus: form.paymentMethod === 'cash' ? 'pending_cash' : 'paid',
        fulfillmentType,
        kitchenNotes:  form.kitchenNotes || null,
        driverNotes:   fulfillmentType === 'delivery' ? (form.driverNotes || null) : null,
        couponCode:    appliedPromo?.code || null,
        toppings:      cart.toppings,
        total:         finalTotal,
        createdAt:     new Date().toISOString(),
      });
      if (form.name && !auth.name)
        localStorage.setItem('pizzaAuth', JSON.stringify({ ...auth, name: form.name }));
      localStorage.removeItem('cart');
      navigate('/success');
    } catch { alert('שגיאה בשליחת ההזמנה'); }
    finally { setLoading(false); }
  };

  const inputCls = "w-full border border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:border-dark bg-gray-50 text-dark text-sm transition";

  return (
    <form onSubmit={handleSubmit} className="max-w-md mx-auto min-h-screen bg-white">

      {/* ── Header ── */}
      <div className="bg-white border-b border-gray-100 px-5 py-4 flex items-center relative">
        <button type="button" onClick={() => navigate('/cart')} className="absolute right-4">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none"
            stroke="#1A1A1A" strokeWidth="1.8" strokeLinecap="round">
            <path d="M19 12H5M12 19l-7-7 7-7"/>
          </svg>
        </button>
        <div className="flex-1 text-center">
          <span className="font-black text-xl tracking-widest text-dark">PIZZA STORY</span>
        </div>
      </div>

      <div className="px-4 pt-5 pb-10 space-y-5">

        {/* ══ STEP 1 — How ═══════════════════════════════════════════════════ */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
          <div className="flex items-center gap-3 mb-4">
            <StepBadge n={1} done={false} />
            <span className="font-black text-dark text-base">איך תרצו לקבל?</span>
          </div>
          <div className="flex gap-3">
            <BigOption active={fulfillmentType === 'delivery'} onClick={() => setFulfillmentType('delivery')}
              emoji="🛵" title={he.delivery_label} sub={`+${DELIVERY_FEE}₪`} />
            <BigOption active={fulfillmentType === 'pickup'} onClick={() => setFulfillmentType('pickup')}
              emoji="🏪" title={he.pickup} sub="חינם" />
          </div>
          {fulfillmentType === 'pickup' && (
            <div className="mt-3 bg-gray-50 border border-gray-100 rounded-xl px-4 py-3 text-xs text-gray-500 flex items-center gap-2">
              <svg width="13" height="13" viewBox="0 0 24 24" fill="none"
                stroke="#9ca3af" strokeWidth="2" strokeLinecap="round">
                <path d="M21 10c0 7-9 13-9 13S3 17 3 10a9 9 0 0118 0z"/>
                <circle cx="12" cy="10" r="3"/>
              </svg>
              {he.store_address}
            </div>
          )}
        </div>

        {/* ══ STEP 2 — Contact ════════════════════════════════════════════════ */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5 space-y-4">
          <div className="flex items-center gap-3 mb-1">
            <StepBadge n={2} done={false} />
            <span className="font-black text-dark text-base">פרטי קשר</span>
          </div>

          <div>
            <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase tracking-wider">{he.name}</label>
            <input name="name" value={form.name} onChange={handleChange} required
              placeholder="שם מלא" className={inputCls} />
          </div>

          <div>
            <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase tracking-wider">{he.phone}</label>
            <input name="phone" type="tel" value={form.phone} onChange={handleChange}
              required placeholder="050-0000000" dir="ltr" className={inputCls} />
          </div>

          {fulfillmentType === 'delivery' && (
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase tracking-wider">{he.address}</label>
              <input name="address" value={form.address} onChange={handleChange}
                required placeholder="רחוב, מספר, עיר" className={inputCls} />
              {addressPrefilled && (
                <p className="text-xs mt-1 font-medium" style={{ color: '#22c55e' }}>
                  ✓ מולאה מהזמנה קודמת
                </p>
              )}
            </div>
          )}
        </div>

        {/* ══ STEP 3 — Notes ══════════════════════════════════════════════════ */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5 space-y-4">
          <div className="flex items-center gap-3 mb-1">
            <StepBadge n={3} done={false} />
            <span className="font-black text-dark text-base">הערות (אופציונלי)</span>
          </div>

          <div>
            <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase tracking-wider">{he.kitchen_notes}</label>
            <textarea name="kitchenNotes" value={form.kitchenNotes} onChange={handleChange}
              rows={2} placeholder="לדוגמה: ללא גלוטן, לא חריף..."
              className={`${inputCls} resize-none`} />
          </div>

          {fulfillmentType === 'delivery' && (
            <div>
              <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase tracking-wider">{he.driver_notes}</label>
              <textarea name="driverNotes" value={form.driverNotes} onChange={handleChange}
                rows={2} placeholder="לדוגמה: קומה 3, אינטרקום 12..."
                className={`${inputCls} resize-none`} />
            </div>
          )}
        </div>

        {/* ══ STEP 4 — Payment ════════════════════════════════════════════════ */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
          <div className="flex items-center gap-3 mb-4">
            <StepBadge n={4} done={false} />
            <span className="font-black text-dark text-base">אופן תשלום</span>
          </div>
          <div className="flex gap-3">
            <BigOption active={form.paymentMethod === 'cash'}
              onClick={() => setForm(f => ({ ...f, paymentMethod: 'cash' }))}
              emoji="💵" title={fulfillmentType === 'pickup' ? 'מזומן בעסק' : 'מזומן לשליח'} />
            <BigOption active={form.paymentMethod === 'credit'}
              onClick={() => setForm(f => ({ ...f, paymentMethod: 'credit' }))}
              emoji="💳" title="כרטיס אשראי" />
          </div>
        </div>

        {/* ══ Promo Code ══════════════════════════════════════════════════════ */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
          <button
            type="button"
            className="w-full flex items-center justify-between text-sm font-bold text-dark"
            onClick={() => setShowPromo(s => !s)}
          >
            <span className="flex items-center gap-2">
              <span
                className="w-7 h-7 rounded-full flex items-center justify-center text-xs"
                style={{ background: '#FFC10720' }}
              >🏷️</span>
              {he.promo_code}
            </span>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none"
              stroke="#9ca3af" strokeWidth="2" strokeLinecap="round">
              <polyline points={showPromo ? "18 15 12 9 6 15" : "6 9 12 15 18 9"}/>
            </svg>
          </button>

          {showPromo && (
            <div className="mt-3">
              {appliedPromo ? (
                <div className="flex items-center gap-2 bg-green-50 border border-green-100 rounded-xl px-3 py-2.5">
                  <span className="text-green-700 text-sm font-bold flex-1">
                    ✓ {appliedPromo.label} ({appliedPromo.code})
                  </span>
                  <button type="button" onClick={removePromo}
                    className="text-xs text-gray-400 hover:text-red-500">הסר</button>
                </div>
              ) : (
                <div className="flex gap-2">
                  <input value={promoInput} dir="ltr"
                    onChange={e => { setPromoInput(e.target.value); setPromoError(''); }}
                    onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), applyPromo())}
                    placeholder="הכנס קוד..."
                    className="flex-1 border border-gray-200 rounded-xl px-3 py-2.5 focus:outline-none focus:border-dark bg-gray-50 text-sm uppercase transition"
                  />
                  <button type="button" onClick={applyPromo}
                    className="font-black text-dark px-4 rounded-xl text-sm transition active:scale-95"
                    style={{ background: '#FFC107' }}>
                    החל
                  </button>
                </div>
              )}
              {promoError && <p className="text-red-500 text-xs mt-1">{promoError}</p>}
              <p className="text-xs text-gray-400 mt-1.5">PIZZA10 · PIZZA20 · FREESHIP</p>
            </div>
          )}
        </div>

        {/* ══ Price Summary ═══════════════════════════════════════════════════ */}
        <div className="bg-dark rounded-2xl p-5 space-y-2.5">
          <p className="text-white/50 text-xs font-bold uppercase tracking-wider mb-3">סיכום מחיר</p>

          <div className="flex justify-between text-sm text-white/70">
            <span>🍕 פיצה + תוספות</span><span>{baseTotal}₪</span>
          </div>
          {fulfillmentType === 'delivery' && (
            <div className="flex justify-between text-sm text-white/70">
              <span>🛵 דמי משלוח</span>
              <span>
                {isFreeShip
                  ? <><span className="line-through opacity-40">{DELIVERY_FEE}₪</span><span className="text-green-400 font-bold mr-1">חינם</span></>
                  : `${DELIVERY_FEE}₪`}
              </span>
            </div>
          )}
          {discountAmt > 0 && (
            <div className="flex justify-between text-sm font-semibold" style={{ color: GOLD }}>
              <span>🏷️ הנחה ({appliedPromo.code})</span><span>-{discountAmt}₪</span>
            </div>
          )}
          <div className="flex justify-between items-center pt-3 border-t border-white/10">
            <span className="text-white font-black text-lg">סה"כ לתשלום</span>
            <span className="font-black text-2xl" style={{ color: GOLD }}>{finalTotal}₪</span>
          </div>
        </div>

        {/* ══ Submit ══════════════════════════════════════════════════════════ */}
        <button
          type="submit"
          disabled={loading}
          className="w-full font-black text-dark text-xl py-5 rounded-full shadow-sm transition active:scale-95 disabled:opacity-50"
          style={{ background: loading ? '#e5e7eb' : GOLD }}
        >
          {loading ? 'שולח הזמנה...' : `בצע הזמנה · ${finalTotal}₪`}
        </button>
      </div>
    </form>
  );
}
